/** Fuel operations ledger. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';requireAuth();enforceModuleAccess('fuel');$rows=getDb()->query('SELECT f.*,v.registration_number,t.trip_number,s.name station_name FROM fuel_logs f JOIN vehicles v ON v.id=f.vehicle_id LEFT JOIN trips t ON t.id=f.trip_id LEFT JOIN fuel_stations s ON s.id=f.fuel_station_id WHERE f.deleted_at IS NULL ORDER BY f.logged_date DESC')->fetchAll();$pageTitle='Fuel logs';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';?><main class="main-content fuel-module"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><div><h1 class="page-title">Fuel management</h1><p class="page-subtitle">Monitor consumption, unit cost, and refueling accountability.</p></div><a class="btn btn-primary" href="add.php">Log fuel</a></section><section class="card table-card"><div class="table-responsive"><table class="fuel-table"><thead><tr><th>Log</th><th>Vehicle</th><th>Trip</th><th>Station</th><th>Type</th><th>Liters</th><th>Unit cost</th><th>Total</th><th>Date</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['fuel_code']?:'#'.$r['id'])?></td><td><?=e($r['registration_number'])?></td><td><?=e($r['trip_number']?:'—')?></td><td><?=e($r['station_name']?:'—')?></td><td><?=e($r['fuel_type'])?></td><td><?=e((string)$r['quantity_liters'])?></td><td><?=e(formatCurrency((float)$r['price_per_liter']))?></td><td><?=e(formatCurrency((float)$r['cost']))?></td><td><?=e(formatDate($r['logged_date']))?></td><td><a href="view.php?id=<?=$r['id']?>"><i class="fa fa-eye"></i></a></td></tr><?php endforeach;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
